func TestVerifyFixedBaseMatchesGenericReference(t *testing.T) {
	privKey, err := GenerateKey(rand.New(rand.NewSource(0))) //#nosec G404 deterministic test seed
	if err != nil {
		t.Fatal(err)
	}
	pubKey := privKey.PublicKey

	message := []byte("message")
	signature, err := privKey.Sign(message, sha256.New())
	if err != nil {
		t.Fatal(err)
	}

	var sig Signature
	if _, err := sig.SetBytes(signature); err != nil {
		t.Fatal(err)
	}

	curveParams := twistededwards.GetEdwardsCurve()
	var cofactor, scalar big.Int
	curveParams.Cofactor.BigInt(&cofactor)
	scalar.SetBytes(sig.S[:])

	var lhsFixed, lhsGeneric twistededwards.PointAffine
	lhsFixed.ScalarMultiplicationBase(&scalar).
		ScalarMultiplication(&lhsFixed, &cofactor)
	lhsGeneric.ScalarMultiplication(&curveParams.Base, &scalar).
		ScalarMultiplication(&lhsGeneric, &cofactor)
	if !lhsFixed.Equal(&lhsGeneric) {
		t.Fatal("[S]Base mismatch against generic reference")
	}

	ok, err := pubKey.Verify(signature, message, sha256.New())
	if err != nil {
		t.Fatal(err)
	}
	if !ok {
		t.Fatal("Verify correct signature should return true")
	}

	ok, err = pubKey.Verify(signature, []byte("wrong_message"), sha256.New())
	if err != nil {
		t.Fatal(err)
	}
	if ok {
		t.Fatal("Verify wrong signature should be false")
	}
}

func TestNonMalleability(t *testing.T) {

	// buffer too big
	t.Run("buffer_overflow", func(t *testing.T) {
		bsig := make([]byte, 2*sizeFr+1)
		var sig Signature
		_, err := sig.SetBytes(bsig)
		if err != errWrongSize {
			t.Fatal("should raise wrong size error")
		}
	})

	// R overflows p_mod
	t.Run("R_overflow", func(t *testing.T) {
		bsig := make([]byte, 2*sizeFr)
		frMod := fr.Modulus()
		r := big.NewInt(1)
		r.Add(frMod, r)
		buf := r.Bytes()
		for i := range sizeFr {
			bsig[sizeFr-1-i] = buf[i]
		}

		var sig Signature
		_, err := sig.SetBytes(bsig)
		if err != errRBiggerThanPMod {
			t.Fatal("should raise error r >= p_mod")
		}
	})

	// S overflows r_mod
	t.Run("S_overflow", func(t *testing.T) {
		bsig := make([]byte, 2*sizeFr)
		o := big.NewInt(1)
		cp := twistededwards.GetEdwardsCurve()
		o.Add(&cp.Order, o)
		buf := o.Bytes()
		copy(bsig[sizeFr:], buf[:])
		big.NewInt(1).FillBytes(bsig[:sizeFr])

		var sig Signature
		_, err := sig.SetBytes(bsig)
		if err != errSBiggerThanRMod {
			t.Fatal("should raise error s >= r_mod")
		}
	})

}

